scwin.f_PopUp = async function (disGubun, chgGubun) {
  switch (disGubun) {
    case "Customer":
      udc_cn.ilCommonPopUp(scwin.callbackCustomer, ed_cncd.getValue().trim(), txt_cnnm.getValue(), chgGubun, "5", "Customer", "140,300", null, null, "500", "500", null, null, null, "F", "Customer Search,Customer Code,Customer Name");
      break;
    case "Customer2":
      udc_bilgClnt.ilCommonPopUp(scwin.callbackCustomer2, cnd_ed_bilgClntNo.getValue().trim(), cnd_txt_bilgClntNm.getValue(), chgGubun, "5", "Customer", "140,300", null, null, "500", "500", null, null, null, "F", "Customer Search,Customer Code,Customer Name");
      break;
    case "Pic":
      let pParam = ed_cncd.getValue().trim();
      if (pParam == "") {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, ["Customer"]);
        ed_cncd.setFocus();
        return;
      }
      udc_an.ilCommonPopUp(scwin.callbackPic, ed_anno.getValue().trim(), txt_annm.getValue(), chgGubun, "4", "PIC", "100,350", null, pParam, "500", "500", null, null, null, "T", null);
      break;
    case "Bic":
      udc_adminPic.ilCommonPopUp(scwin.callbackBic, ed_adminPic.getValue().trim(), txt_adminPicNm.getValue(), chgGubun, "5", "BIC", "100,100,,,100", "3,4,6,7,8,9,10", null, "500", "500", null, null, null, "F", null);
      break;
    case "Department":
      udc_dept.ilCommonPopUp(scwin.callbackDepartment, ed_dept.getValue().trim(), txt_deptnm.getValue(), "T", "2", "Code, Name", "80,230", "3,4,5,6,7,8,9,10", null, null, null, null, null, null, "F", "Department,Code,Name", "F");
      break;
    case "B/L PIC":
      udc_pic.ilCommonPopUp(scwin.callbackBlPic, cnd_ed_picNo.getValue().trim(), cnd_txt_picNm.getValue(), chgGubun, "5", "PIC", "100,100,,,100", "3,4,6,7,8,9,10", null, "500", "500", null, null, null, "F", null);
      break;
    default:
      break;
  }
};
